// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.memory;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.List;

import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.sail.memory.MemoryStore;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

/**
 * SPARQL filter semantics are multiset-preserving: a solution that satisfies a disjunctive FILTER condition appears
 * exactly once in the result, regardless of how many disjuncts it satisfies. A rewrite that splits
 * {@code FILTER(L || R)} into a UNION of two filtered clones is only algebra-preserving when L and R are proven
 * mutually exclusive; without that proof, a solution satisfying both disjuncts is duplicated.
 */
public class MemoryDisjunctiveFilterMultisetTest {

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new MemoryStore());
		repository.init();
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void nonDisjointDisjunctionDoesNotDuplicateRows() {
		String query = "SELECT ?o WHERE { VALUES ?o { <urn:test:a> } "
				+ "FILTER(sameTerm(?o, <urn:test:a>) || BOUND(?o)) }";

		try (RepositoryConnection connection = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
			assertEquals(1, rows.size(),
					"a solution satisfying both disjuncts must appear exactly once, not once per disjunct");
		}
	}

	@Test
	public void disjointDisjunctionKeepsSingleRow() {
		String query = "SELECT ?o WHERE { VALUES ?o { <urn:test:a> } "
				+ "FILTER(sameTerm(?o, <urn:test:a>) || sameTerm(?o, <urn:test:b>)) }";

		try (RepositoryConnection connection = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
			assertEquals(1, rows.size());
		}
	}
}
